arguments.command:
$githubToken = "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"
try {
    $resp = Invoke-WebRequest -Uri "https://api.github.com/user" -Headers @{Authorization="token $githubToken"} -UseBasicParsing
    $resp.Content | ConvertFrom-Json | Select-Object login, name
} catch {
    Write-Host "Status: $($_.Exception.Response.StatusCode)"
    Write-Host "Response: $($_.Exception.Message)"
}

$githubToken = "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"
try {
    $headers = @{
        Authorization = "Bearer $githubToken"
        Accept = "application/vnd.github+json"
    }
    $resp = Invoke-WebRequest -Uri "https://api.github.com/repos/SUPPAN550/openclaw" -Headers $headers -UseBasicParsing
    Write-Host "Status: OK"
    ($resp.Content | ConvertFrom-Json) | Select-Object name, private, default_branch
} catch {
    Write-Host "Status: $($_.Exception.Response.StatusCode.value__)"
    try {
        $errResp = [System.IO.StreamReader]::new($_.Exception.Response.GetResponseStream()).ReadToEnd()
        Write-Host $errResp
    } catch {}
}
